"use client";

import { useState } from "react";
import { Header } from "@/components/ui/Header";
import { VoiceRecorder } from "@/components/voice/VoiceRecorder";
import { CourseOutline } from "@/components/course/CourseOutline";
import { GeneratingAnimation } from "@/components/ui/Loading";
import { useCourseStore } from "@/lib/store/course-store";

const EXAMPLE_QUERIES = [
  { hi: "Python programming seekho", en: "Learn Python programming" },
  { hi: "Data Science kya hai", en: "What is Data Science" },
  { hi: "Web development seekho", en: "Learn Web Development" },
  { hi: "Machine Learning basics", en: "Machine Learning basics" },
  { hi: "Digital marketing seekho", en: "Learn Digital Marketing" },
  { hi: "English speaking practice", en: "English speaking practice" },
];

export default function HomePage() {
  const [inputText, setInputText] = useState("");
  const [level, setLevel] = useState("beginner");
  const { currentCourse, isGenerating, error, language, generateCourse, setError } = useCourseStore();

  const handleSubmit = async () => {
    if (!inputText.trim()) return;
    await generateCourse(inputText.trim(), level);
  };

  const handleVoiceTranscript = (text: string) => {
    setInputText(text);
  };

  const handleExampleClick = (query: typeof EXAMPLE_QUERIES[0]) => {
    const text = language === "hi" ? query.hi : query.en;
    setInputText(text);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  if (isGenerating) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
        <Header />
        <GeneratingAnimation />
      </div>
    );
  }

  if (currentCourse) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
        <Header />
        <div className="py-4 px-4 flex justify-center">
          <button
            onClick={() => useCourseStore.getState().setCourse(null)}
            className="text-sm text-orange-600 hover:text-orange-700 flex items-center gap-1"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            New Search
          </button>
        </div>
        <CourseOutline course={currentCourse} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-orange-50 to-white">
      <Header />

      <main className="max-w-2xl mx-auto px-4 pt-12 pb-20">
        {/* Hero */}
        <div className="text-center mb-10">
          <h2 className="text-3xl sm:text-4xl font-bold text-gray-900 mb-3">
            {language === "hi" ? "कुछ भी सीखो, मुफ़्त में" : "Learn Anything, For Free"}
          </h2>
          <p className="text-gray-500 text-lg">
            {language === "hi"
              ? "AI से बना structured course plan — YouTube, NPTEL, Khan Academy से"
              : "AI-powered structured courses from YouTube, NPTEL, Khan Academy"}
          </p>
        </div>

        {/* Input Section */}
        <div className="bg-white rounded-2xl shadow-lg shadow-orange-100/50 border border-orange-100 p-6">
          <div className="flex items-end gap-3">
            <div className="flex-1">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {language === "hi" ? "आप क्या सीखना चाहते हैं?" : "What do you want to learn?"}
              </label>
              <textarea
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={
                  language === "hi"
                    ? "उदाहरण: मुझे Python programming सीखना है..."
                    : "Example: I want to learn Python programming..."
                }
                rows={2}
                className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-400 focus:border-transparent resize-none text-gray-800 placeholder:text-gray-400"
              />
            </div>
            <VoiceRecorder onTranscript={handleVoiceTranscript} disabled={isGenerating} />
          </div>

          {/* Level selector */}
          <div className="flex items-center gap-2 mt-4">
            <span className="text-sm text-gray-500">
              {language === "hi" ? "स्तर:" : "Level:"}
            </span>
            {["beginner", "intermediate", "advanced"].map((l) => (
              <button
                key={l}
                onClick={() => setLevel(l)}
                className={
                  "px-3 py-1 rounded-full text-sm transition-colors " +
                  (level === l
                    ? "bg-orange-500 text-white"
                    : "bg-gray-100 text-gray-600 hover:bg-gray-200")
                }
              >
                {l === "beginner"
                  ? language === "hi" ? "शुरुआती" : "Beginner"
                  : l === "intermediate"
                  ? language === "hi" ? "मध्यम" : "Intermediate"
                  : language === "hi" ? "उन्नत" : "Advanced"}
              </button>
            ))}
          </div>

          {/* Submit */}
          <button
            onClick={handleSubmit}
            disabled={!inputText.trim() || isGenerating}
            className="w-full mt-4 py-3 bg-gradient-to-r from-orange-500 to-orange-600 text-white font-semibold rounded-xl hover:from-orange-600 hover:to-orange-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-[0.98]"
          >
            {language === "hi" ? "Course बनाओ" : "Generate Course"}
          </button>

          {error && (
            <div className="mt-3 p-3 bg-red-50 text-red-700 rounded-lg text-sm flex items-center justify-between">
              <span>{error}</span>
              <button onClick={() => setError(null)} className="text-red-500 hover:text-red-700">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          )}
        </div>

        {/* Example Queries */}
        <div className="mt-8">
          <p className="text-sm text-gray-400 text-center mb-3">
            {language === "hi" ? "या कोई example try करो:" : "Or try an example:"}
          </p>
          <div className="flex flex-wrap justify-center gap-2">
            {EXAMPLE_QUERIES.map((q, i) => (
              <button
                key={i}
                onClick={() => handleExampleClick(q)}
                className="px-4 py-2 bg-white border border-gray-200 rounded-full text-sm text-gray-600 hover:border-orange-300 hover:text-orange-600 transition-colors"
              >
                {language === "hi" ? q.hi : q.en}
              </button>
            ))}
          </div>
        </div>

        {/* Bottom branding */}
        <div className="mt-16 text-center">
          <p className="text-xs text-gray-400">
            {language === "hi"
              ? "YouTube, NPTEL, Khan Academy, MIT OCW से मुफ्त content"
              : "Free content from YouTube, NPTEL, Khan Academy, MIT OCW"}
          </p>
          <div className="flex justify-center gap-4 mt-3 opacity-40">
            <span className="text-xs font-medium text-gray-500">YouTube</span>
            <span className="text-xs font-medium text-gray-500">NPTEL</span>
            <span className="text-xs font-medium text-gray-500">Khan Academy</span>
            <span className="text-xs font-medium text-gray-500">MIT OCW</span>
          </div>
        </div>
      </main>
    </div>
  );
}
