export interface Course {
  courseId: string;
  title: string;
  titleHindi: string;
  description: string;
  duration: string;
  level: 'beginner' | 'intermediate' | 'advanced';
  modules: Module[];
  prerequisites: string[];
  totalHours: number;
  language: string;
  createdAt: string;
}

export interface Module {
  week: number;
  title: string;
  titleHindi: string;
  topics: string[];
  resources: Resource[];
  estimatedHours: number;
}

export interface Resource {
  id: string;
  type: 'youtube' | 'nptel' | 'mit-ocw' | 'khan-academy' | 'swayam';
  title: string;
  url: string;
  duration: string;
  language: string;
  channel?: string;
  thumbnail?: string;
  views?: number;
}

export interface VoiceInput {
  text: string;
  language: string;
  confidence: number;
}

export type SupportedLanguage = 'hi' | 'en' | 'ta' | 'te' | 'bn' | 'mr' | 'gu' | 'kn' | 'ml' | 'pa' | 'or';

