'use client';

import { Course } from '@/types/course';
import { ModuleCard } from './ModuleCard';
import { TextToSpeechPlayer } from '../voice/TextToSpeechPlayer';
import { useCourseStore } from '@/lib/store/course-store';

interface CourseOutlineProps {
  course: Course;
}

export function CourseOutline({ course }: CourseOutlineProps) {
  const { language } = useCourseStore();

  return (
    <div className="max-w-3xl mx-auto px-4 py-6">
      <div className="mb-8">
        <div className="flex items-start justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900">
              {language === 'hi' ? course.titleHindi || course.title : course.title}
            </h2>
            <p className="text-gray-600 mt-2">{course.description}</p>
          </div>
          <TextToSpeechPlayer
            text={language === 'hi' ? course.titleHindi || course.title : course.title}
            language={language}
          />
        </div>

        <div className="flex flex-wrap gap-3 mt-4">
          <span className="px-3 py-1 bg-orange-50 text-orange-700 rounded-full text-sm font-medium">
            {course.duration}
          </span>
          <span className="px-3 py-1 bg-green-50 text-green-700 rounded-full text-sm font-medium capitalize">
            {course.level}
          </span>
          <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-sm font-medium">
            {course.totalHours} hours
          </span>
          <span className="px-3 py-1 bg-purple-50 text-purple-700 rounded-full text-sm font-medium">
            100% Free
          </span>
        </div>

        {course.prerequisites.length > 0 && (
          <div className="mt-4 p-3 bg-yellow-50 rounded-lg">
            <p className="text-sm text-yellow-800">
              <span className="font-medium">Prerequisites: </span>
              {course.prerequisites.join(', ')}
            </p>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {course.modules.map((module, index) => (
          <ModuleCard key={index} module={module} language={language} />
        ))}
      </div>
    </div>
  );
}
