import { Resource } from '@/types/course';

interface ResourceListProps {
  resources: Resource[];
}

export function ResourceList({ resources }: ResourceListProps) {
  return (
    <div className="space-y-2">
      <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Resources</h4>
      {resources.map((resource, index) => (
        <a
          key={index}
          href={resource.url}
          target="_blank"
          rel="noopener noreferrer"
          className="flex items-start gap-3 p-3 rounded-lg hover:bg-gray-50 transition-colors group"
        >
          {resource.thumbnail && (
            <img
              src={resource.thumbnail}
              alt=""
              className="w-24 h-14 object-cover rounded-md flex-shrink-0"
            />
          )}
          <div className="min-w-0 flex-1">
            <p className="text-sm font-medium text-gray-800 group-hover:text-orange-600 transition-colors line-clamp-2">
              {resource.title}
            </p>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-xs text-gray-500">{resource.channel}</span>
              {resource.duration && (
                <span className="text-xs text-gray-400">{resource.duration}</span>
              )}
              {resource.views ? (
                <span className="text-xs text-gray-400">
                  {resource.views > 1000000
                    ? (resource.views / 1000000).toFixed(1) + 'M views'
                    : resource.views > 1000
                    ? (resource.views / 1000).toFixed(0) + 'K views'
                    : resource.views + ' views'}
                </span>
              ) : null}
            </div>
            <span className="inline-block mt-1 px-1.5 py-0.5 bg-red-50 text-red-600 rounded text-[10px] font-medium uppercase">
              {resource.type}
            </span>
          </div>
        </a>
      ))}
    </div>
  );
}
